import { useState, useMemo, useCallback } from "react";
import { useTranslation } from "react-i18next";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Checkbox } from "@/components/ui/checkbox";
import { Skeleton } from "@/components/ui/skeleton";
import { Card, CardContent } from "@/components/ui/card";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { TypeCombobox } from "@/components/admin/TypeCombobox";
import { useAllRestaurantTypes } from "@/hooks/useAllRestaurantTypes";
import { Search, Save, X, Plus, Loader2, Tags, ChevronLeft, ChevronRight } from "lucide-react";
import { toast } from "sonner";

const PAGE_SIZE = 30;

type CategoryValue = "architecture" | "food" | "hotel";

interface LandmarkRow {
  id: string;
  name: string;
  name_en: string | null;
  address: string | null;
  city: string | null;
  type: string[] | null;
  category: string | null;
  landmark_types: string[] | null;
  cuisine_types: string[] | null;
  dining_features: string[] | null;
  hotel_features: string[] | null;
}

type TagsMap = Record<string, string[]>;
type CategoryMap = Record<string, string>;

const CATEGORY_OPTIONS: { value: CategoryValue; labelKey: string; defaultLabel: string }[] = [
  { value: "architecture", labelKey: "category.architecture", defaultLabel: "建筑" },
  { value: "food", labelKey: "category.food", defaultLabel: "美食" },
  { value: "hotel", labelKey: "category.hotel", defaultLabel: "酒店" },
];

/** Pick the subtype field that matches a row's category. */
function subtypeFieldFor(category: string | null | undefined):
  | "landmark_types"
  | "cuisine_types"
  | "hotel_features"
  | "type" {
  if (category === "architecture") return "landmark_types";
  if (category === "food") return "cuisine_types";
  if (category === "hotel") return "hotel_features";
  return "type";
}

function readSubtypes(row: LandmarkRow, category: string | null | undefined): string[] {
  const field = subtypeFieldFor(category);
  const v = (row as any)[field];
  if (Array.isArray(v) && v.length) return v;
  // Fallback: legacy 'type' if subtype empty
  return Array.isArray(row.type) ? row.type : [];
}

export default function AdminLandmarkTags() {
  const { t } = useTranslation();
  const queryClient = useQueryClient();
  const { data: existingTypes } = useAllRestaurantTypes();

  const [search, setSearch] = useState("");
  const [cityFilter, setCityFilter] = useState<string>("all");
  const [categoryFilter, setCategoryFilter] = useState<string>("all");
  const [page, setPage] = useState(1);
  const [edits, setEdits] = useState<TagsMap>({});
  const [cityEdits, setCityEdits] = useState<Record<string, string>>({});
  const [categoryEdits, setCategoryEdits] = useState<CategoryMap>({});
  const [selected, setSelected] = useState<Set<string>>(new Set());
  const [savingIds, setSavingIds] = useState<Set<string>>(new Set());
  const [bulkAction, setBulkAction] = useState<"replace" | "add" | "remove" | "setCategory">("setCategory");
  const [bulkValue, setBulkValue] = useState("");
  const [bulkCategory, setBulkCategory] = useState<CategoryValue>("architecture");
  const [bulkLoading, setBulkLoading] = useState(false);

  const { data: landmarks = [], isLoading } = useQuery({
    queryKey: ["admin-landmark-tags"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("restaurants")
        .select(
          "id, name, name_en, address, city, type, category, landmark_types, cuisine_types, dining_features, hotel_features"
        )
        .eq("template", "landmark")
        .order("name", { ascending: true });
      if (error) throw error;
      return (data || []) as LandmarkRow[];
    },
  });

  const cities = useMemo(() => {
    const set = new Set<string>();
    landmarks.forEach((l) => l.city && set.add(l.city));
    return Array.from(set).sort();
  }, [landmarks]);

  const filtered = useMemo(() => {
    const q = search.trim().toLowerCase();
    return landmarks.filter((l) => {
      if (cityFilter !== "all" && l.city !== cityFilter) return false;
      if (categoryFilter !== "all") {
        const cat = categoryEdits[l.id] !== undefined ? categoryEdits[l.id] : l.category;
        if (categoryFilter === "__none__") {
          if (cat) return false;
        } else if (cat !== categoryFilter) {
          return false;
        }
      }
      if (!q) return true;
      const cat = categoryEdits[l.id] !== undefined ? categoryEdits[l.id] : l.category;
      const subs = readSubtypes(l, cat);
      return (
        l.name?.toLowerCase().includes(q) ||
        l.name_en?.toLowerCase().includes(q) ||
        l.address?.toLowerCase().includes(q) ||
        subs.some((tg) => tg?.toLowerCase().includes(q))
      );
    });
  }, [landmarks, search, cityFilter, categoryFilter, categoryEdits]);

  const totalPages = Math.max(1, Math.ceil(filtered.length / PAGE_SIZE));
  const currentPage = Math.min(page, totalPages);
  const pageData = filtered.slice((currentPage - 1) * PAGE_SIZE, currentPage * PAGE_SIZE);

  const getCategory = useCallback(
    (l: LandmarkRow): string => {
      if (categoryEdits[l.id] !== undefined) return categoryEdits[l.id];
      return l.category || "";
    },
    [categoryEdits]
  );

  const getTags = useCallback(
    (l: LandmarkRow): string[] => {
      if (edits[l.id] !== undefined) return edits[l.id];
      return readSubtypes(l, getCategory(l));
    },
    [edits, getCategory]
  );

  const isTagsDirty = useCallback(
    (l: LandmarkRow): boolean => {
      if (edits[l.id] === undefined) return false;
      const a = (edits[l.id] || []).filter(Boolean);
      const b = readSubtypes(l, getCategory(l)).filter(Boolean);
      if (a.length !== b.length) return true;
      return a.some((v, i) => v !== b[i]);
    },
    [edits, getCategory]
  );

  const updateTag = (id: string, index: number, value: string) => {
    setEdits((prev) => {
      const row = landmarks.find((l) => l.id === id);
      const baseline = row ? readSubtypes(row, getCategory(row)) : [];
      const current = prev[id] !== undefined ? [...prev[id]] : [...baseline];
      current[index] = value;
      return { ...prev, [id]: current };
    });
  };

  const addTag = (id: string) => {
    setEdits((prev) => {
      const row = landmarks.find((l) => l.id === id);
      const baseline = row ? readSubtypes(row, getCategory(row)) : [];
      const current = prev[id] !== undefined ? [...prev[id]] : [...baseline];
      if (current.length >= 5) return prev;
      current.push("");
      return { ...prev, [id]: current };
    });
  };

  const removeTag = (id: string, index: number) => {
    setEdits((prev) => {
      const row = landmarks.find((l) => l.id === id);
      const baseline = row ? readSubtypes(row, getCategory(row)) : [];
      const current = prev[id] !== undefined ? [...prev[id]] : [...baseline];
      current.splice(index, 1);
      return { ...prev, [id]: current };
    });
  };

  const getCity = useCallback(
    (l: LandmarkRow): string => {
      if (cityEdits[l.id] !== undefined) return cityEdits[l.id];
      return l.city || "";
    },
    [cityEdits]
  );

  const isCityDirty = useCallback(
    (l: LandmarkRow): boolean => {
      if (cityEdits[l.id] === undefined) return false;
      return (cityEdits[l.id] || "") !== (l.city || "");
    },
    [cityEdits]
  );

  const isCategoryDirty = useCallback(
    (l: LandmarkRow): boolean => {
      if (categoryEdits[l.id] === undefined) return false;
      return (categoryEdits[l.id] || "") !== (l.category || "");
    },
    [categoryEdits]
  );

  const updateCity = (id: string, value: string) => {
    setCityEdits((prev) => ({ ...prev, [id]: value }));
  };

  const updateCategory = (id: string, value: string) => {
    setCategoryEdits((prev) => ({ ...prev, [id]: value }));
  };

  const resetRow = (id: string) => {
    setEdits((prev) => {
      const next = { ...prev };
      delete next[id];
      return next;
    });
    setCityEdits((prev) => {
      const next = { ...prev };
      delete next[id];
      return next;
    });
    setCategoryEdits((prev) => {
      const next = { ...prev };
      delete next[id];
      return next;
    });
  };

  /** Build update payload writing tags into the field matching the (effective) category. */
  const buildTagsPayload = (effectiveCategory: string, tags: string[]) => {
    const field = subtypeFieldFor(effectiveCategory);
    const payload: any = {};
    if (field === "landmark_types") {
      payload.landmark_types = tags;
      payload.landmark_types_en = tags;
      payload.landmark_types_pt = tags;
    } else if (field === "cuisine_types") {
      payload.cuisine_types = tags;
      payload.cuisine_types_en = tags;
      payload.cuisine_types_pt = tags;
    } else if (field === "hotel_features") {
      payload.hotel_features = tags;
      payload.hotel_features_en = tags;
      payload.hotel_features_pt = tags;
    } else {
      payload.type = tags;
      payload.type_en = tags;
      payload.type_pt = tags;
    }
    return payload;
  };

  const saveRow = async (l: LandmarkRow) => {
    const effectiveCategory = getCategory(l);
    const tags = (edits[l.id] !== undefined ? edits[l.id] : readSubtypes(l, effectiveCategory))
      .map((s) => s.trim())
      .filter(Boolean);
    const newCity = cityEdits[l.id] !== undefined ? cityEdits[l.id].trim() : l.city;
    setSavingIds((prev) => new Set(prev).add(l.id));
    try {
      const payload: any = {};
      if (cityEdits[l.id] !== undefined) payload.city = newCity || null;
      if (categoryEdits[l.id] !== undefined) {
        payload.category = categoryEdits[l.id] || null;
      }
      if (edits[l.id] !== undefined) {
        Object.assign(payload, buildTagsPayload(effectiveCategory, tags));
      }
      const { error } = await supabase.from("restaurants").update(payload).eq("id", l.id);
      if (error) throw error;
      toast.success(t("admin.landmarkTagsPage.savedOne", "已保存"));
      resetRow(l.id);
      queryClient.invalidateQueries({ queryKey: ["admin-landmark-tags"] });
    } catch (e: any) {
      toast.error(e.message || t("common.error"));
    } finally {
      setSavingIds((prev) => {
        const n = new Set(prev);
        n.delete(l.id);
        return n;
      });
    }
  };

  const dirtyIds = useMemo(() => {
    const ids = new Set<string>();
    Object.keys(edits).forEach((id) => {
      const l = landmarks.find((x) => x.id === id);
      if (l && isTagsDirty(l)) ids.add(id);
    });
    Object.keys(cityEdits).forEach((id) => {
      const l = landmarks.find((x) => x.id === id);
      if (l && isCityDirty(l)) ids.add(id);
    });
    Object.keys(categoryEdits).forEach((id) => {
      const l = landmarks.find((x) => x.id === id);
      if (l && isCategoryDirty(l)) ids.add(id);
    });
    return Array.from(ids);
  }, [edits, cityEdits, categoryEdits, landmarks, isTagsDirty, isCityDirty, isCategoryDirty]);

  const saveAllDirty = async () => {
    if (dirtyIds.length === 0) return;
    setBulkLoading(true);
    try {
      let ok = 0;
      let fail = 0;
      for (const id of dirtyIds) {
        const l = landmarks.find((x) => x.id === id);
        if (!l) continue;
        const effectiveCategory =
          categoryEdits[id] !== undefined ? categoryEdits[id] : l.category || "";
        const payload: any = {};
        if (edits[id] !== undefined) {
          const tags = edits[id].map((s) => s.trim()).filter(Boolean);
          Object.assign(payload, buildTagsPayload(effectiveCategory, tags));
        }
        if (cityEdits[id] !== undefined) {
          payload.city = (cityEdits[id] || "").trim() || null;
        }
        if (categoryEdits[id] !== undefined) {
          payload.category = categoryEdits[id] || null;
        }
        const { error } = await supabase.from("restaurants").update(payload).eq("id", id);
        if (error) fail++;
        else ok++;
      }
      toast.success(
        t("admin.landmarkTagsPage.bulkSaveResult", "已保存 {{ok}} 条，失败 {{fail}} 条", { ok, fail })
      );
      setEdits({});
      setCityEdits({});
      setCategoryEdits({});
      queryClient.invalidateQueries({ queryKey: ["admin-landmark-tags"] });
    } finally {
      setBulkLoading(false);
    }
  };

  const toggleSelect = (id: string) => {
    setSelected((prev) => {
      const n = new Set(prev);
      if (n.has(id)) n.delete(id);
      else n.add(id);
      return n;
    });
  };

  const toggleSelectAllVisible = () => {
    setSelected((prev) => {
      const n = new Set(prev);
      const allOn = pageData.every((l) => n.has(l.id));
      if (allOn) pageData.forEach((l) => n.delete(l.id));
      else pageData.forEach((l) => n.add(l.id));
      return n;
    });
  };

  const applyBulk = async () => {
    if (selected.size === 0) {
      toast.error(t("admin.landmarkTagsPage.selectAtLeastOne", "请至少选择一项"));
      return;
    }
    if (bulkAction !== "setCategory") {
      const value = bulkValue.trim();
      if (!value && bulkAction !== "replace") {
        toast.error(t("admin.landmarkTagsPage.enterTagValue", "请输入标签值"));
        return;
      }
    }
    setBulkLoading(true);
    try {
      let ok = 0;
      let fail = 0;
      for (const id of selected) {
        const l = landmarks.find((x) => x.id === id);
        if (!l) continue;
        let payload: any = {};
        if (bulkAction === "setCategory") {
          payload.category = bulkCategory;
        } else {
          const value = bulkValue.trim();
          const effectiveCategory =
            categoryEdits[id] !== undefined ? categoryEdits[id] : l.category || "";
          const current = getTags(l).filter(Boolean);
          let next: string[] = current;
          if (bulkAction === "replace") {
            next = value ? [value] : [];
          } else if (bulkAction === "add") {
            if (!current.includes(value)) {
              next = [...current, value].slice(0, 5);
            }
          } else if (bulkAction === "remove") {
            next = current.filter((tg) => tg !== value);
          }
          payload = buildTagsPayload(effectiveCategory, next);
        }
        const { error } = await supabase.from("restaurants").update(payload).eq("id", id);
        if (error) fail++;
        else ok++;
      }
      toast.success(
        t("admin.landmarkTagsPage.bulkApplyResult", "批量更新成功 {{ok}}，失败 {{fail}}", { ok, fail })
      );
      setEdits({});
      setSelected(new Set());
      setBulkValue("");
      queryClient.invalidateQueries({ queryKey: ["admin-landmark-tags"] });
    } finally {
      setBulkLoading(false);
    }
  };

  const suggestions = existingTypes?.uniqueZh || [];

  const tagsColumnLabel = (cat: string) => {
    if (cat === "food")
      return t("admin.landmarkTagsPage.colTagsFood", "菜系");
    if (cat === "hotel")
      return t("admin.landmarkTagsPage.colTagsHotel", "酒店特色");
    if (cat === "architecture")
      return t("admin.landmarkTagsPage.colTagsArch", "地标类型");
    return t("admin.landmarkTagsPage.colTagsLegacy", "标签");
  };

  return (
    <div className="container mx-auto py-6 space-y-5 max-w-[1400px]">
      {/* Header */}
      <div className="flex items-center gap-2">
        <Tags className="h-5 w-5 text-primary" />
        <h1 className="text-xl font-semibold">
          {t("admin.landmarkTagsPage.title", "建筑标签批量管理")}
        </h1>
      </div>

      {/* Toolbar (filters + bulk + save-all) — single compact row */}
      <div className="rounded-lg border border-border bg-card p-3 space-y-2.5">
        {/* Filters row */}
        <div className="flex flex-wrap gap-2 items-center">
          <div className="relative flex-1 min-w-[220px] max-w-sm">
            <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
            <Input
              value={search}
              onChange={(e) => {
                setSearch(e.target.value);
                setPage(1);
              }}
              placeholder={t("admin.landmarkTagsPage.searchPlaceholder", "搜索名称、地址或标签")}
              className="pl-8 h-9"
            />
          </div>
          <Select
            value={categoryFilter}
            onValueChange={(v) => {
              setCategoryFilter(v);
              setPage(1);
            }}
          >
            <SelectTrigger className="w-[150px] h-9">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">{t("admin.landmarkTagsPage.allCategories", "全部大类")}</SelectItem>
              <SelectItem value="__none__">{t("admin.landmarkTagsPage.noCategoryOption", "（未设置）")}</SelectItem>
              {CATEGORY_OPTIONS.map((opt) => (
                <SelectItem key={opt.value} value={opt.value}>
                  {t(opt.labelKey, opt.defaultLabel)}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
          <Select
            value={cityFilter}
            onValueChange={(v) => {
              setCityFilter(v);
              setPage(1);
            }}
          >
            <SelectTrigger className="w-[160px] h-9">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">{t("admin.landmarkTagsPage.allCities", "全部城市")}</SelectItem>
              {cities.map((c) => (
                <SelectItem key={c} value={c}>
                  {c}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
          <div className="text-xs text-muted-foreground ml-auto">
            {t("admin.landmarkTagsPage.totalCount", "共 {{count}} 条", { count: filtered.length })}
          </div>
        </div>

        {/* Bulk row */}
        <div className="flex flex-wrap gap-2 items-center pt-1 border-t border-border/60">
          <span className="text-xs text-muted-foreground">
            {t("admin.landmarkTagsPage.selected", "已选")}{" "}
            <span className="font-medium text-foreground">{selected.size}</span>
          </span>
          <Select value={bulkAction} onValueChange={(v) => setBulkAction(v as any)}>
            <SelectTrigger className="w-[140px] h-9">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="setCategory">{t("admin.landmarkTagsPage.actionSetCategory", "设置大类")}</SelectItem>
              <SelectItem value="add">{t("admin.landmarkTagsPage.actionAdd", "添加标签")}</SelectItem>
              <SelectItem value="remove">{t("admin.landmarkTagsPage.actionRemove", "移除标签")}</SelectItem>
              <SelectItem value="replace">{t("admin.landmarkTagsPage.actionReplace", "替换为单一标签")}</SelectItem>
            </SelectContent>
          </Select>
          {bulkAction === "setCategory" ? (
            <Select value={bulkCategory} onValueChange={(v) => setBulkCategory(v as CategoryValue)}>
              <SelectTrigger className="w-[160px] h-9">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                {CATEGORY_OPTIONS.map((opt) => (
                  <SelectItem key={opt.value} value={opt.value}>
                    {t(opt.labelKey, opt.defaultLabel)}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          ) : (
            <div className="w-[220px]">
              <TypeCombobox
                placeholder={t("admin.landmarkTagsPage.tagPlaceholder", "标签值")}
                value={bulkValue}
                onChange={setBulkValue}
                suggestions={suggestions}
              />
            </div>
          )}
          <Button size="sm" onClick={applyBulk} disabled={bulkLoading || selected.size === 0}>
            {bulkLoading && <Loader2 className="h-3.5 w-3.5 mr-1 animate-spin" />}
            {t("admin.landmarkTagsPage.apply", "执行")}
          </Button>
          {selected.size > 0 && (
            <Button variant="ghost" size="sm" onClick={() => setSelected(new Set())}>
              {t("admin.landmarkTagsPage.clearSelection", "清空选择")}
            </Button>
          )}
          <div className="ml-auto flex items-center gap-2">
            {dirtyIds.length > 0 && (
              <span className="text-xs text-muted-foreground">
                {t("admin.landmarkTagsPage.unsaved", "未保存")}{" "}
                <span className="font-medium text-foreground">{dirtyIds.length}</span>
              </span>
            )}
            <Button
              size="sm"
              onClick={saveAllDirty}
              disabled={bulkLoading || dirtyIds.length === 0}
            >
              <Save className="h-3.5 w-3.5 mr-1" />
              {t("admin.landmarkTagsPage.saveAll", "保存全部")}
            </Button>
          </div>
        </div>
      </div>

      {/* Table */}
      <Card className="overflow-hidden">
        <CardContent className="p-0">
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead className="w-[40px]">
                  <Checkbox
                    checked={pageData.length > 0 && pageData.every((l) => selected.has(l.id))}
                    onCheckedChange={toggleSelectAllVisible}
                  />
                </TableHead>
                <TableHead className="min-w-[220px]">
                  {t("admin.landmarkTagsPage.colName", "建筑名称")}
                </TableHead>
                <TableHead className="w-[130px]">
                  {t("admin.landmarkTagsPage.colCategory", "大类")}
                </TableHead>
                <TableHead className="w-[160px]">
                  {t("admin.landmarkTagsPage.colCity", "城市")}
                </TableHead>
                <TableHead className="min-w-[420px]">
                  {t("admin.landmarkTagsPage.colSubtypes", "子类标签")}
                </TableHead>
                <TableHead className="w-[140px] text-right">
                  {t("admin.landmarkTagsPage.colActions", "操作")}
                </TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {isLoading ? (
                Array.from({ length: 6 }).map((_, i) => (
                  <TableRow key={i}>
                    <TableCell colSpan={6}>
                      <Skeleton className="h-10 w-full" />
                    </TableCell>
                  </TableRow>
                ))
              ) : pageData.length === 0 ? (
                <TableRow>
                  <TableCell colSpan={6} className="text-center text-muted-foreground py-8">
                    {t("admin.landmarkTagsPage.empty", "暂无数据")}
                  </TableCell>
                </TableRow>
              ) : (
                pageData.map((l) => {
                  const tags = getTags(l);
                  const tagsDirty = isTagsDirty(l);
                  const cityDirty = isCityDirty(l);
                  const catDirty = isCategoryDirty(l);
                  const dirty = tagsDirty || cityDirty || catDirty;
                  const saving = savingIds.has(l.id);
                  const cat = getCategory(l);
                  return (
                    <TableRow key={l.id} className={dirty ? "bg-primary/5" : ""}>
                      <TableCell>
                        <Checkbox
                          checked={selected.has(l.id)}
                          onCheckedChange={() => toggleSelect(l.id)}
                        />
                      </TableCell>
                      <TableCell>
                        <div className="font-medium text-sm">{l.name}</div>
                        {l.name_en && (
                          <div className="text-xs text-muted-foreground">{l.name_en}</div>
                        )}
                        {l.address && (
                          <div className="text-xs text-muted-foreground line-clamp-1">{l.address}</div>
                        )}
                      </TableCell>
                      <TableCell>
                        <Select
                          value={cat || "__unset__"}
                          onValueChange={(v) => updateCategory(l.id, v === "__unset__" ? "" : v)}
                        >
                          <SelectTrigger className={`h-9 ${catDirty ? "border-primary" : ""}`}>
                            <SelectValue
                              placeholder={t("admin.landmarkTagsPage.unsetCategory", "未设置")}
                            />
                          </SelectTrigger>
                          <SelectContent>
                            <SelectItem value="__unset__">
                              {t("admin.landmarkTagsPage.unsetCategory", "未设置")}
                            </SelectItem>
                            {CATEGORY_OPTIONS.map((opt) => (
                              <SelectItem key={opt.value} value={opt.value}>
                                {t(opt.labelKey, opt.defaultLabel)}
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                      </TableCell>
                      <TableCell>
                        <Input
                          value={getCity(l)}
                          onChange={(e) => updateCity(l.id, e.target.value)}
                          placeholder={t("admin.landmarkTagsPage.cityPlaceholder", "城市")}
                          list={`cities-${l.id}`}
                          className={`h-9 ${cityDirty ? "border-primary" : ""}`}
                        />
                        <datalist id={`cities-${l.id}`}>
                          {cities.map((c) => (
                            <option key={c} value={c} />
                          ))}
                        </datalist>
                      </TableCell>
                      <TableCell>
                        <div className="space-y-1.5">
                          <div className="text-[11px] uppercase tracking-wide text-muted-foreground">
                            {tagsColumnLabel(cat)}
                          </div>
                          <div className="flex flex-wrap gap-1.5 items-center">
                            {tags.length === 0 && (
                              <span className="text-xs text-muted-foreground italic">
                                {t("admin.landmarkTagsPage.noTags", "无标签")}
                              </span>
                            )}
                            {tags.map((tg, idx) => (
                              <div key={idx} className="flex items-center gap-0.5">
                                <div className="w-[160px]">
                                  <TypeCombobox
                                    placeholder={t("admin.typeExample")}
                                    value={tg}
                                    onChange={(v) => updateTag(l.id, idx, v)}
                                    suggestions={suggestions}
                                  />
                                </div>
                                <Button
                                  type="button"
                                  variant="ghost"
                                  size="icon"
                                  className="h-7 w-7"
                                  onClick={() => removeTag(l.id, idx)}
                                  aria-label="remove"
                                >
                                  <X className="h-3.5 w-3.5" />
                                </Button>
                              </div>
                            ))}
                            {tags.length < 5 && (
                              <Button
                                type="button"
                                variant="outline"
                                size="sm"
                                className="h-7 px-2"
                                onClick={() => addTag(l.id)}
                              >
                                <Plus className="h-3 w-3 mr-1" />
                                {t("admin.addType")}
                              </Button>
                            )}
                          </div>
                        </div>
                      </TableCell>
                      <TableCell className="text-right">
                        <div className="flex justify-end gap-1.5">
                          {dirty && (
                            <Button
                              variant="ghost"
                              size="sm"
                              onClick={() => resetRow(l.id)}
                              disabled={saving}
                            >
                              {t("common.cancel")}
                            </Button>
                          )}
                          <Button
                            size="sm"
                            onClick={() => saveRow(l)}
                            disabled={!dirty || saving}
                          >
                            {saving ? (
                              <Loader2 className="h-3 w-3 animate-spin" />
                            ) : (
                              <Save className="h-3 w-3 mr-1" />
                            )}
                            {t("common.save")}
                          </Button>
                        </div>
                      </TableCell>
                    </TableRow>
                  );
                })
              )}
            </TableBody>
          </Table>
        </CardContent>
      </Card>

      {totalPages > 1 && (
        <div className="flex items-center justify-center gap-2">
          <Button
            variant="outline"
            size="sm"
            onClick={() => setPage((p) => Math.max(1, p - 1))}
            disabled={currentPage === 1}
          >
            <ChevronLeft className="h-4 w-4" />
          </Button>
          <span className="text-sm text-muted-foreground px-2">
            {currentPage} / {totalPages}
          </span>
          <Button
            variant="outline"
            size="sm"
            onClick={() => setPage((p) => Math.min(totalPages, p + 1))}
            disabled={currentPage === totalPages}
          >
            <ChevronRight className="h-4 w-4" />
          </Button>
        </div>
      )}
    </div>
  );
}
